import React, { lazy, Suspense, useEffect, useReducer } from 'react'
import { getAnonSession } from '@fs/zion-session'
import getPermission from '@fs/zion-permissions'
import { splunk } from '@fs/zion-splunk-logger'
import { useSyncedRef } from '@fs/zion-frontend-friends'
import LoadingSpinner from './LoadingSpinner'

const PersonalDataError = lazy(() => import('./PersonalDataError'))
const GenericError = lazy(() => import('./GenericError'))

const perm = 'CanAddPersonalDataPermission'
const context = 'FamilyTree'

const initialState = { loading: true, isAuthorized: false, error: false }
const reducer = (state, action) => {
  switch (action.type) {
    case 'SUCCESS':
      return { loading: false, isAuthorized: action.isAuthorized }
    case 'ERROR':
      return { loading: false, isAuthorized: true, error: true }
    default:
      throw new Error(`Type ${action.type} was not handled by router reducer.`)
  }
}

export default function PersonalDataCheck({ SuccessComponent, LoadingComponent, path, ...props }) {
  const [{ loading, error, isAuthorized }, dispatch] = useReducer(reducer, initialState)
  const LoadingEl = LoadingComponent || LoadingSpinner

  const loggingInfoRef = useSyncedRef({
    message: 'Personal data check not authorized!',
    path,
  })

  useEffect(() => {
    let isMounted = true
    const check = async () => {
      // create an anonymous session if session doesn't already exist
      await getAnonSession()
      // get permission to add personal data
      const data = await getPermission(perm, context)

      isMounted && dispatch({ type: 'SUCCESS', isAuthorized: data.authorized })
      isMounted && !data.authorized && splunk.log(loggingInfoRef.current)
    }

    check().catch(() => {
      // If the cas call or the anonymous session call fail, we let them through
      isMounted && dispatch({ type: 'ERROR' })
    })

    return () => {
      isMounted = false
    }
  }, [loggingInfoRef])

  if (loading) return <LoadingEl />

  if (error)
    return (
      <Suspense fallback={<LoadingEl />}>
        <GenericError />
      </Suspense>
    )

  if (!isAuthorized)
    return (
      <Suspense fallback={<LoadingEl />}>
        <PersonalDataError />
      </Suspense>
    )

  return <SuccessComponent {...{ ...props, path, LoadingComponent }} />
}
